const query = $json.query || {};
const body = $json.body || $json;
const message = query.message || body.message || body.goal || '';
const projectId = query.project_id || body.project_id || ('proj-' + Date.now());
return [{ json: { message, project_id: projectId, operation: 'init', goal: message } }];

const operation = $json.operation || 'get';
const projectId = $json.project_id;
if (!projectId) return [{ json: { error: 'project_id required' } }];
const store = $getWorkflowStaticData('global');
if (operation === 'init') {
  if (store[projectId]) return [{ json: { ...store[projectId], already_exists: true } }];
  store[projectId] = {
    project_id: projectId,
    goal: $json.goal || '',
    status: 'active',
    completed_tasks: [],
    pending_tasks: [],
    files: [],
    created_at: new Date().toISOString(),
    last_updated: new Date().toISOString()
  };
  return [{ json: store[projectId] }];
}
if (operation === 'get') {
  return [{ json: store[projectId] || { project_id: projectId, exists: false } }];
}
if (operation === 'set') {
  const existing = store[projectId] || {};
  store[projectId] = { ...existing, ...$json.state, project_id: projectId, last_updated: new Date().toISOString() };
  return [{ json: store[projectId] }];
}
return [{ json: { error: `Unknown operation: ${operation}` } }];

// MODIFIED: Absorbs Research: Build Project Context
// Caches _allFileContents, _researchDocs, _projectFileList in static data
// so Phase 2 chunks don't need to re-fetch or re-compute.
const memory = $('Init Memory').first().json;
const message = $('Extract Input').first().json.message;
const allFiles = $json.files || [];
const staticData = $getWorkflowStaticData('global');

// Cache all file contents for Phase 2
staticData._allFileContents = allFiles;

const fileList = allFiles.map(f => f.path);

// Build API surface (exports from each file)
const apiSurface = [];
for (const f of allFiles) {
  if (!f.path.match(/\.(ts|tsx|js|jsx)$/) || f.path.includes('node_modules')) continue;
  const lines = (f.content || '').split('\n');
  const exports = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^export\s+default\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').substring(0, 120));
    } else if (/^export\s+(const|let|var|function|class|interface|type|enum)\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').replace(/=>[\s\S]*$/, '=> ...').substring(0, 150));
    } else if (/^export\s+\{/.test(trimmed)) {
      exports.push(trimmed.substring(0, 150));
    }
  }
  if (exports.length > 0) {
    apiSurface.push(`## ${f.path}\n${exports.join('\n')}`);
  }
}

// Extract dependencies from package.json
let dependencies = {};
let devDependencies = {};
let depNames = [];
for (const f of allFiles) {
  if (f.path === 'package.json' || f.path.endsWith('/package.json')) {
    try {
      const pkg = JSON.parse(f.content);
      dependencies = { ...dependencies, ...(pkg.dependencies || {}) };
      devDependencies = { ...devDependencies, ...(pkg.devDependencies || {}) };
      depNames = [...Object.keys(pkg.dependencies || {}), ...Object.keys(pkg.devDependencies || {})];
    } catch(e) {}
  }
}

// Build research docs string
const depList = Object.entries(dependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
const devDepList = Object.entries(devDependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
let researchDocs = '';
if (depList || devDepList) {
  researchDocs += '## Dependency Manifest\nOnly use packages listed here.\n';
  if (depList) researchDocs += `dependencies:\n${depList}\n`;
  if (devDepList) researchDocs += `devDependencies:\n${devDepList}\n`;
}
if (apiSurface.length > 0) {
  researchDocs += '\n## Project API Surface\nMatch these import/export signatures exactly when importing from project files.\n';
  researchDocs += apiSurface.join('\n\n');
}

// Cache for all downstream phases
staticData._researchDocs = researchDocs;
staticData._projectFileList = fileList;
staticData._projectApiSummary = apiSurface.join('\n');
staticData._projectDeps = depNames;

return [{ json: {
  message,
  project_goal: memory.goal || message,
  project_id: memory.project_id,
  existing_files: fileList,
  api_summary: apiSurface.join('\n'),
  installed_packages: depNames
} }];

const message = $json.message || '';
const existingFiles = $json.existing_files || [];
const apiSummary = $json.api_summary || '';
const installedPkgs = $json.installed_packages || [];

let projectContext = '';
if (existingFiles.length > 0) {
  projectContext += `

EXISTING PROJECT FILES (only reference files from this list):
${existingFiles.join('
')}
`;
}
if (apiSummary) {
  projectContext += `
API SURFACE (exports from each file):
${apiSummary}
`;
}
if (installedPkgs.length > 0) {
  projectContext += `
INSTALLED PACKAGES (only reference packages from this list):
${installedPkgs.join(', ')}
`;
}

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{
      role: 'user',
      content: `You are a Senior Software Architect. Your job is to break a coding request into MULTIPLE structured tasks. Each task will be handled by a separate coder who writes files in batches of 2.

Request: ${message}${projectContext}

Output a JSON object with ONE field:

"tasks": array of task objects. IMPORTANT: You MUST create multiple tasks. Group files by concern (e.g. styles in one task, frontend components in another, config in another). Each task has:
- task_id: string like "TASK-001"
- description: detailed actionable description of what to implement, including specific requirements, color values, component names, API endpoints, and behavior. The coder cannot see the original request — your description is all they get.
- files: array of exact file paths to create or modify. List EVERY file this task needs — the coder can ONLY write files listed here. Only use file paths from the EXISTING PROJECT FILES list above.
- dependencies: array of task_id strings this task depends on (empty if none)
- complexity: "low", "medium", or "high"

RULES:
- Always split work across multiple tasks by concern: styles, components, routes, config, etc.
- Each task should touch at most 3-4 files
- The description must be SELF-CONTAINED — include ALL details the coder needs
- Only reference files from the EXISTING PROJECT FILES list. Only reference packages from the INSTALLED PACKAGES list.
- Detect the project type from the files and packages. If the project is a React/Vite frontend (no Express or backend framework in INSTALLED PACKAGES), focus all tasks on frontend files. Only create server/middleware/API handler tasks if Express or a similar backend framework is in INSTALLED PACKAGES.
- In each task description, specify the EXACT import/export style each file should use (named vs default) based on the API SURFACE above.
- Output ONLY the raw JSON object: {"tasks": [...]}
- No markdown, no explanation — ONLY the JSON with tasks`
    }],
    temperature: 0.6,
    top_p: 0.95,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: 32768
  }
}];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/<\/?task>/g, '').trim();
content = content.replace(/\n+(?:Reasoning|Note|Explanation):[\s\S]*/i, '').trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let tasks, planDocument = '';
try {
  const parsed = JSON.parse(content);
  if (Array.isArray(parsed)) {
    tasks = parsed;
  } else {
    tasks = parsed.tasks || [parsed];
    planDocument = parsed.plan_document || '';
  }
} catch (e) {
  // Truncated JSON recovery: extract complete task objects
  const tasksMatch = content.match(/"tasks"\s*:\s*\[/);
  if (tasksMatch) {
    const arrStart = content.indexOf('[', tasksMatch.index);
    let bracketDepth = 0;
    let lastCompleteObj = -1;
    for (let i = arrStart; i < content.length; i++) {
      if (content[i] === '{') bracketDepth++;
      if (content[i] === '}') {
        bracketDepth--;
        if (bracketDepth === 0) lastCompleteObj = i;
      }
    }
    if (lastCompleteObj > arrStart) {
      const recoveredArr = content.substring(arrStart, lastCompleteObj + 1) + ']';
      try {
        tasks = JSON.parse(recoveredArr);
      } catch (e2) {
        tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
      }
    } else {
      tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
    }
  } else {
    tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
  }
}

tasks = tasks.map(t => ({
  ...t,
  files: t.files || [],
  dependencies: t.dependencies || [],
  complexity: t.complexity || 'medium'
}));

return [{ json: { tasks, plan_document: planDocument } }];

// MODIFIED: Absorbs Split Into Chunks. Builds flat (task, chunk) queue.
// Queue is passed through data pipeline (not static data) to avoid stale reads after HTTP nodes.
const tasks = $json.tasks || [];
const planDocument = $json.plan_document || '';
const plannerInput = $('Prepare Planner Input').first().json;
const projectId = plannerInput.project_id;
const projectGoal = plannerInput.project_goal;

// Topological sort
const taskMap = new Map();
tasks.forEach(t => taskMap.set(t.task_id, t));
const inDegree = new Map();
const dependents = new Map();
tasks.forEach(t => {
  inDegree.set(t.task_id, 0);
  dependents.set(t.task_id, []);
});
tasks.forEach(t => {
  const deps = (t.dependencies || []).filter(d => taskMap.has(d));
  inDegree.set(t.task_id, deps.length);
  deps.forEach(d => dependents.get(d).push(t.task_id));
});
const topoQueue = [];
tasks.forEach(t => {
  if (inDegree.get(t.task_id) === 0) topoQueue.push(t.task_id);
});
const sorted = [];
while (topoQueue.length > 0) {
  const id = topoQueue.shift();
  sorted.push(taskMap.get(id));
  for (const dep of (dependents.get(id) || [])) {
    inDegree.set(dep, inDegree.get(dep) - 1);
    if (inDegree.get(dep) === 0) topoQueue.push(dep);
  }
}
if (sorted.length < tasks.length) {
  const sortedIds = new Set(sorted.map(t => t.task_id));
  tasks.forEach(t => { if (!sortedIds.has(t.task_id)) sorted.push(t); });
}

// Flatten into (task, chunk) queue — 2 files per chunk
const chunkSize = 2;
const queue = [];
for (const task of sorted) {
  const taskFiles = task.files || [];
  const chunks = [];
  for (let i = 0; i < taskFiles.length; i += chunkSize) {
    chunks.push(taskFiles.slice(i, i + chunkSize));
  }
  if (chunks.length === 0) chunks.push([]);
  for (const chunkFiles of chunks) {
    queue.push({
      task,
      chunk_files: chunkFiles,
      project_id: projectId,
      project_goal: projectGoal,
      plan_document: planDocument
    });
  }
}

const staticData = $getWorkflowStaticData('global');
staticData.p2Results = [];
staticData.allTasks = sorted;

if (queue.length === 0) {
  return [{ json: { task: { task_id: 'NONE', description: 'No tasks', files: [] }, chunk_files: [], project_id: projectId, project_goal: projectGoal, plan_document: planDocument, _p2Queue: [] } }];
}
// Pass remaining queue items through data pipeline instead of static data
const first = queue[0];
first._p2Queue = queue.slice(1);
return [{ json: first }];

// P2: Stash Context — passes through all fields including _p2Queue for loop control
return [{ json: {
  task: $json.task,
  chunk_files: $json.chunk_files,
  project_id: $json.project_id,
  project_goal: $json.project_goal,
  plan_document: $json.plan_document,
  _p2Queue: $json._p2Queue || []
} }];

// NEW: Replaces Chunk: Read Existing Files + Research: Build Project Context + Chunk: Build Code Input
// Uses $() node reference for task context, static data only for cached file contents
const staticData = $getWorkflowStaticData('global');
const stashed = $('P2: Stash Context').first().json;
const chunkFiles = stashed.chunk_files || [];
const allFiles = staticData._allFileContents || [];

// Get existing content for files in this chunk
const existingFiles = chunkFiles.length > 0
  ? allFiles.filter(f => chunkFiles.includes(f.path))
  : [];

const task = { ...(stashed.task || {}) };
if (chunkFiles.length > 0) task.files = chunkFiles;

return [{ json: {
  task,
  existing_files: existingFiles,
  plan_document: stashed.plan_document || '',
  project_goal: stashed.project_goal || '',
  project_id: stashed.project_id,
  research_docs: staticData._researchDocs || ''
} }];

// MODIFIED: Removed retry/feedback logic (that's Phase 4 now)
// Removed hardcoded tech stack, uses positive language
const input = $json;
const planDocument = input.plan_document || '';

let taskDescription = input.task?.description || input.description || '';
if (!taskDescription && input.task?.raw_output) {
  const raw = input.task.raw_output;
  const cleaned = raw.replace(/<\/?task>/g, '').replace(/\n+(?:Reasoning|Note):[\s\S]*/i, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    const list = Array.isArray(parsed) ? parsed : (parsed.tasks || []);
    taskDescription = list.map(t => `${t.task_id}: ${t.description}`).join('\n\n');
  } catch(e) { taskDescription = raw; }
}

const taskFiles = (input.task || {}).files || [];
const filesConstraint = taskFiles.length > 0
  ? '\n\nFILES TO MODIFY (only output these files):\n' + taskFiles.join('\n')
  : '';

const existingFiles = input.existing_files || [];
const existingFilesSection = existingFiles.length > 0
  ? '\n\nEXISTING PROJECT FILES (only modify files that need changes):\n' +
    existingFiles.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n')
  : '';

const userContent = `Task:\n${taskDescription}${filesConstraint}${existingFilesSection}`;

let systemMessage = `You are a Senior Full-Stack Developer. Output ONLY the files that need to be created or changed. Skip files that are already correct.\n\nFor EACH file you need to create or modify, output EXACTLY this format:\n### path/to/file.ts\n\`\`\`ts\n[complete file content]\n\`\`\`\n\nRULES:\n- Only output files that this task requires you to create or change\n- Output complete file content (not diffs)\n- No explanations, no numbered lists, no prose — ONLY the file blocks\n- Only output files listed in the FILES TO MODIFY section\n- CRITICAL: Only use packages found in the Dependency Manifest below. If you need functionality from a package not in the manifest, use built-in browser/Node APIs or the listed packages instead.\n- CRITICAL: Match import styles to the source module. Use named imports ({ X }) for named exports, default imports for default exports. Check the EXISTING PROJECT FILES to confirm each module's export style.\n- Preserve each file's existing export style (named vs default) when modifying it`;

if (planDocument) {
  systemMessage += `\n\nARCHITECTURE REFERENCE (follow this plan):\n${planDocument}`;
}

const researchDocs = input.research_docs || '';
if (researchDocs) {
  systemMessage += `\n\nPROJECT CONTEXT (from research agent):\n${researchDocs}`;
}

return [{ json: {
  model: $env.CODER_MODEL || 'qwen/qwen3-30b-a3b-2507',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userContent }
  ],
  temperature: 0.7,
  top_p: 0.8,
  top_k: 20,
  min_p: 0.0,
  presence_penalty: 0.0,
  repeat_penalty: 1.05,
  max_tokens: 16384
} }];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) {
  content = content.split('</think>').pop().trim();
}
const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*(?:\.\w[\w.-]*|[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|txt|lock|toml|cfg|ini)|Dockerfile|Makefile|LICENSE|CHANGELOG))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path)) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}
const stashed = $('P2: Stash Context').first().json;
return [{ json: { files, task: stashed.task, project_id: stashed.project_id, project_goal: stashed.project_goal } }];

// NEW: Replaces Chunk: Prepare Write
// Simplified write prep + updates _allFileContents cache so later chunks see fresh content
const stashed = $('P2: Stash Context').first().json;
const chunkFiles = stashed.chunk_files || [];
const newFiles = $json.files || [];
const projectId = $json.project_id || stashed.project_id;

// Include all files the Code Writer produced
let filteredFiles = newFiles;

// Handle package.json merge: preserve existing deps, add new ones
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
for (const newFile of filteredFiles) {
  if (newFile.path === 'package.json' || newFile.path.endsWith('/package.json')) {
    const existing = allFiles.find(f => f.path === newFile.path);
    if (existing) {
      try {
        const existingPkg = JSON.parse(existing.content);
        const newPkg = JSON.parse(newFile.content);
        newPkg.dependencies = { ...(existingPkg.dependencies || {}), ...(newPkg.dependencies || {}) };
        newPkg.devDependencies = { ...(existingPkg.devDependencies || {}), ...(newPkg.devDependencies || {}) };
        newFile.content = JSON.stringify(newPkg, null, 2);
      } catch(e) {}
    }
  }
}

// Update the in-memory file cache so later chunks see fresh content
for (const newFile of filteredFiles) {
  const idx = allFiles.findIndex(f => f.path === newFile.path);
  if (idx >= 0) {
    allFiles[idx] = { path: newFile.path, content: newFile.content };
  } else {
    allFiles.push({ path: newFile.path, content: newFile.content });
  }
}
staticData._allFileContents = allFiles;

if (filteredFiles.length === 0) {
  return [{ json: { project_id: projectId, files: [], _skipWrite: true } }];
}

return [{ json: { project_id: projectId, files: filteredFiles } }];

// Accumulates results, checks remaining queue from data pipeline (not static data)
const staticData = $getWorkflowStaticData('global');
const stashed = $('P2: Stash Context').first().json;
const task = stashed.task || {};
const taskId = task.task_id || 'unknown';
const chunkFiles = stashed.chunk_files || [];
const remainingQueue = stashed._p2Queue || [];
const writtenFiles = $json.files_written || ($json.files || []).map(f => f.path || f) || [];

if (!staticData.p2Results) staticData.p2Results = [];
staticData.p2Results.push({
  task_id: taskId,
  chunk_files: chunkFiles,
  files_written: writtenFiles
});

const hasMore = remainingQueue.length > 0;
return [{ json: { _hasMore: hasMore, _p2Queue: remainingQueue, task_id: taskId, files_written: writtenFiles } }];

// Get next item from queue passed through data pipeline
const queue = $json._p2Queue || [];
const next = queue[0] || {};
// Pass remaining queue to next iteration
next._p2Queue = queue.slice(1);
return [{ json: next }];

// NEW: Full-project cross-file review prompt
// Reviewer sees ALL files at once — catches import/export mismatches, type errors, missing deps
const allFiles = $json.files || [];
const staticData = $getWorkflowStaticData('global');
const plannerInput = $('Prepare Planner Input').first().json;
const projectGoal = plannerInput.project_goal || '';
const deps = staticData._projectDeps || [];

// Build tasks summary
const taskSummaries = (staticData.allTasks || []).map(t =>
  `${t.task_id}: ${t.description.substring(0, 200)}`
).join('
');

// Format all files for review
const allFilesFormatted = allFiles
  .filter(f => f.path.match(/\.(ts|tsx|js|jsx|json|css|html)$/) && !f.path.includes('node_modules'))
  .map(f => `### ${f.path}
\`\`\`
${f.content}
\`\`\``)
  .join('

');

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{
      role: 'user',
      content: `You are a Senior Code Reviewer performing a FULL PROJECT REVIEW.
You are reviewing ALL files in the project after all coding tasks have been completed.

Your job is to find cross-file issues that a per-file review would miss:
1. IMPORT/EXPORT MISMATCHES: imports that reference exports that don't exist, wrong import style (named vs default)
2. TYPE MISMATCHES: function signatures that don't match their call sites across files
3. DEPENDENCY ISSUES: imports of packages not in package.json
4. MISSING FILES: components or modules imported but never created
5. CRITICAL BUGS: null reference risks, unhandled promise rejections

Only flag real bugs and cross-file issues, skip style preferences.

Project Goal: ${projectGoal}

Tasks Completed:
${taskSummaries}

Installed Packages: ${deps.join(', ')}

ALL PROJECT FILES:
${allFilesFormatted}

Return ONLY valid JSON (no markdown, no explanation):
{
  "overall_quality": number (0-100),
  "cross_file_consistent": boolean,
  "fixes_needed": [
    {
      "file": "path/to/file.ts",
      "severity": "critical" | "high" | "medium",
      "issue": "description of what is wrong",
      "fix_instruction": "specific instruction for what to change",
      "related_files": ["path/to/other.ts"]
    }
  ],
  "summary": "one paragraph overall assessment"
}

RULES:
- fixes_needed must be an array (empty if everything is clean)
- Each fix must reference a specific file path
- fix_instruction must be actionable — the coder will receive ONLY this instruction and the file content
- related_files lists other files the coder should see for context when fixing this file
- Focus on critical and high severity issues. Skip medium unless fewer than 5 total issues.`
    }],
    temperature: 0.6,
    top_p: 0.95,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: 32768
  }
}];

// NEW: Parses cross-file review format with fixes_needed[]
// Checks reasoning_content as fallback (Qwen 3.5 reasoning model puts output there)
const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
const jsonMatch = content.match(/\{[\s\S]*\}/);
let review;
try {
  review = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch (e) {
  review = { overall_quality: 0, cross_file_consistent: true, fixes_needed: [], summary: 'Review parse failed: ' + content.substring(0, 200) };
}

const fixes = review.fixes_needed || [];
const needsFix = fixes.length > 0 && fixes.some(f => f.severity === 'critical' || f.severity === 'high');
const projectId = $('Prepare Planner Input').first().json.project_id;

const staticData = $getWorkflowStaticData('global');
staticData._reviewResult = review;

return [{ json: {
  review,
  needs_fix: needsFix,
  fixes_needed: fixes,
  project_id: projectId
} }];

// NEW: Builds targeted fix prompt from review feedback
// Only files flagged in fixes_needed get sent to the coder
const fixes = $json.fixes_needed || [];
const projectId = $json.project_id;
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];

// Collect files to fix + related context files
const filesToFix = new Set(fixes.map(f => f.file));
const contextFiles = new Set();
fixes.forEach(f => (f.related_files || []).forEach(rf => contextFiles.add(rf)));

// Build fix instructions
const fixInstructions = fixes.map(f =>
  `FILE: ${f.file}\nSEVERITY: ${f.severity}\nISSUE: ${f.issue}\nFIX: ${f.fix_instruction}`
).join('\n\n');

// Build existing files section
const relevantPaths = new Set([...filesToFix, ...contextFiles]);
const existingFilesSection = allFiles
  .filter(f => relevantPaths.has(f.path))
  .map(f => {
    const marker = filesToFix.has(f.path) ? ' (NEEDS FIX)' : ' (CONTEXT ONLY - read but do not output)';
    return `### ${f.path}${marker}\n\`\`\`\n${f.content}\n\`\`\``;
  })
  .join('\n\n');

const filesToOutput = [...filesToFix];

let systemMessage = `You are a Senior Full-Stack Developer. You are fixing specific issues found during code review.\n\nFor EACH file you fix, output EXACTLY this format:\n### path/to/file.ts\n\`\`\`ts\n[complete file content]\n\`\`\`\n\nRULES:\n- Only output files marked as NEEDS FIX\n- Output complete file content (not diffs)\n- No explanations, no prose — ONLY the file blocks\n- CRITICAL: Only use packages found in the Dependency Manifest below.\n- CRITICAL: Match import styles to the source module exactly.`;

const researchDocs = staticData._researchDocs || '';
if (researchDocs) {
  systemMessage += `\n\nPROJECT CONTEXT:\n${researchDocs}`;
}

const userContent = `Fix the following issues found during code review:\n\n${fixInstructions}\n\nFILES TO FIX (only output these):\n${filesToOutput.join('\n')}\n\nCURRENT FILE CONTENTS:\n${existingFilesSection}`;

return [{ json: {
  model: $env.CODER_MODEL || 'qwen/qwen3-30b-a3b-2507',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userContent }
  ],
  temperature: 0.7,
  top_p: 0.8,
  top_k: 20,
  min_p: 0.0,
  presence_penalty: 0.0,
  repeat_penalty: 1.05,
  max_tokens: 16384,
  _project_id: projectId
} }];

// NEW: Parse fix response, update cache, prepare for write
const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) {
  content = content.split('</think>').pop().trim();
}
const files = [];
const seen = new Set();
const re = /###\s+((?:[\w.-]+\/)*(?:\.\w[\w.-]*|[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|txt|lock|toml|cfg|ini)|Dockerfile|Makefile|LICENSE|CHANGELOG))\s*\n```[\w]*\n([\s\S]*?)```/g;
let m;
while ((m = re.exec(content)) !== null) {
  const path = m[1].trim();
  const fileContent = m[2];
  if (path && !seen.has(path)) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}

// Update in-memory cache
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
for (const newFile of files) {
  const idx = allFiles.findIndex(f => f.path === newFile.path);
  if (idx >= 0) {
    allFiles[idx] = { path: newFile.path, content: newFile.content };
  } else {
    allFiles.push({ path: newFile.path, content: newFile.content });
  }
}
staticData._allFileContents = allFiles;
staticData._fixResults = files.map(f => f.path);

const projectId = $('Prepare Planner Input').first().json.project_id;

if (files.length === 0) {
  return [{ json: { project_id: projectId, files: [], _skipWrite: true } }];
}
return [{ json: { project_id: projectId, files } }];

// MODIFIED: Includes review + fix results from Phase 3 & 4
const staticData = $getWorkflowStaticData('global');
const plannerInput = $('Prepare Planner Input').first().json;
const p2Results = staticData.p2Results || [];
const reviewResult = staticData._reviewResult || {};
const fixResults = staticData._fixResults || [];
const allTasks = staticData.allTasks || [];

// Build task-level results from p2Results
const taskResults = new Map();
for (const r of p2Results) {
  if (!taskResults.has(r.task_id)) {
    const task = allTasks.find(t => t.task_id === r.task_id);
    taskResults.set(r.task_id, {
      task_id: r.task_id,
      description: task ? task.description.substring(0, 200) : '',
      files_written: [],
      chunks_processed: 0
    });
  }
  const entry = taskResults.get(r.task_id);
  entry.files_written.push(...(r.files_written || []));
  entry.chunks_processed++;
}

const allFilesWritten = p2Results.flatMap(r => r.files_written || []);

return [{ json: {
  status: 'completed',
  project_id: plannerInput.project_id,
  project_goal: plannerInput.project_goal,
  tasks_completed: taskResults.size,
  task_results: [...taskResults.values()],
  review: {
    overall_quality: reviewResult.overall_quality || 0,
    cross_file_consistent: reviewResult.cross_file_consistent || false,
    fixes_applied: fixResults,
    summary: reviewResult.summary || ''
  },
  files_written: [...new Set(allFilesWritten)]
} }];

const result = $json;
return [{ json: {
  operation: 'set',
  project_id: result.project_id,
  state: {
    status: 'completed',
    completed_tasks: result.task_results.map(t => t.task_id),
    files: result.files_written
  }
} }];

